'use client'
import { cn, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { ReactNode } from 'react'
import styles from './switcher.module.css'

export interface SwitcherLink {
  label: string
  href: string
  active?: boolean
  icon?: ReactNode
}

export type SwitcherEntry = SwitcherLink | { divider: true }

export interface SwitcherProps {
  items: SwitcherEntry[]
  label?: string
  className?: string | undefined
}

export function Switcher({ items, label, className }: SwitcherProps) {
  useSignals()
  return (
    <ul
      aria-label={label ?? t(builtin.switcher.label)}
      className={cn(styles['switcher'], className)}
    >
      {items.map((entry, i) =>
        'divider' in entry ? (
          // Keep the <li> a real listitem (a <ul> may only contain listitems);
          // the separator role lives on an inner element.
          // eslint-disable-next-line react/no-array-index-key
          <li key={`divider-${i}`}>
            <span role="separator" aria-orientation="horizontal" className={styles['divider']} />
          </li>
        ) : (
          <li key={entry.href}>
            <a
              href={entry.href}
              aria-current={entry.active ? 'page' : undefined}
              data-state={entry.active ? 'active' : undefined}
              className={styles['item']}
            >
              {entry.icon && (
                <span className={styles['icon']} aria-hidden="true">
                  {entry.icon}
                </span>
              )}
              {entry.label}
            </a>
          </li>
        ),
      )}
    </ul>
  )
}

@layer cascivo.component {
  .switcher {
    display: flex;
    flex-direction: column;
    margin: 0;
    padding: 0;
    padding-inline: var(--cascivo-space-2);
    list-style: none;
  }

  .item {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-3);
    padding-inline: var(--cascivo-space-4);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    text-decoration: none;
    border-radius: var(--cascivo-radius-item);
    color: var(--cascivo-color-text-subtle);
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      background: var(--cascivo-color-bg-subtle);
      color: var(--cascivo-color-text);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-state='active'] {
      background: var(--cascivo-color-active-bg);
      color: var(--cascivo-color-text);
      font-weight: var(--cascivo-font-medium);
    }
  }

  .icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }

  .divider {
    display: block;
    block-size: 0;
    margin-block: var(--cascivo-space-2);
    border-block-start: 1px solid var(--cascivo-color-border);
  }
}
